import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { dashboardApi, rpgApi, petApi } from '../services/api';
import { FiTrendingUp, FiBook, FiZap, FiStar } from 'react-icons/fi';

const MOOD_EMOJI = {
  VERY_HAPPY:'😄', HAPPY:'😊', NEUTRAL:'😐', SAD:'😢', VERY_SAD:'😭',
  ANXIOUS:'😰', ANGRY:'😠', HOPEFUL:'🌟', TIRED:'😴', CALM:'😌'
};

export default function DashboardPage() {
  const [data,    setData]    = useState(null);
  const [rpg,     setRpg]     = useState(null);
  const [pet,     setPet]     = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      dashboardApi.get(),
      rpgApi.getProfile().catch(() => null),
      petApi.getStatus().catch(() => null),
    ]).then(([d, r, p]) => {
      setData(d.data.data);
      if (r) setRpg(r.data.data);
      if (p) setPet(p.data.data);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  if (loading) return (
    <div style={{ display:'flex', alignItems:'center', justifyContent:'center', height:'60vh' }}>
      <div style={{ textAlign:'center' }}>
        <div style={{ fontSize:48, marginBottom:16, animation:'float 2s ease-in-out infinite' }}>🌟</div>
        <p style={{ color:'var(--text-secondary)' }}>Loading your world...</p>
      </div>
    </div>
  );

  const user  = data?.user;
  const hour  = new Date().getHours();
  const greeting = hour < 12 ? 'Good morning' : hour < 17 ? 'Good afternoon' : 'Good evening';

  const completedQuests = rpg?.completedQuestsToday || 0;
  const totalQuests     = rpg?.todayQuests?.length   || 0;
  const progressPct     = rpg?.progressPercent       || 0;

  const quickStats = [
    { label:'Journal Entries',  value:data?.journalCount    || 0, icon:<FiBook size={18}/>,     color:'#10b981', bg:'#d1fae5', path:'/journal'   },
    { label:'Gratitudes',       value:data?.gratitudeCount  || 0, icon:<FiStar size={18}/>,     color:'#f59e0b', bg:'#fef3c7', path:'/gratitude'  },
    { label:'Active Habits',    value:data?.habitCount      || 0, icon:<FiZap size={18}/>,      color:'#8b5cf6', bg:'#ede9fe', path:'/habits'     },
    { label:'Focus Mins Today', value:data?.focusMinutesToday||0, icon:<FiTrendingUp size={18}/>,color:'#0ea5e9', bg:'#e0f2fe', path:'/focus'     },
  ];

  const quickActions = [
    { label:'Log Mood',      icon:'😊', path:'/mood',      color:'#0ea5e9', bg:'#e0f2fe' },
    { label:'Write Journal', icon:'📓', path:'/journal',   color:'#10b981', bg:'#d1fae5' },
    { label:'Talk to SAATHI',icon:'🤗', path:'/companion', color:'#f97316', bg:'#ffedd5' },
    { label:'Life RPG',      icon:'⚔️', path:'/rpg',       color:'#7c3aed', bg:'#ede9fe' },
    { label:'Virtual Pet',   icon:'🐾', path:'/pet',       color:'#ec4899', bg:'#fce7f3' },
    { label:'Dream Tower',   icon:'🏰', path:'/dreams',    color:'#f59e0b', bg:'#fef3c7' },
    { label:'Life Journey',  icon:'📖', path:'/journey',   color:'#8b5cf6', bg:'#f5f3ff' },
    { label:'Family Hub',    icon:'❤️', path:'/family',    color:'#ef4444', bg:'#fee2e2' },
    { label:'Gratitude',     icon:'🌱', path:'/gratitude', color:'#84cc16', bg:'#f0fdf4' },
    { label:'Focus Forest',  icon:'🌳', path:'/focus',     color:'#15803d', bg:'#dcfce7' },
    { label:'Community',     icon:'🌍', path:'/community', color:'#06b6d4', bg:'#ecfeff' },
    { label:'Wellness',      icon:'🌿', path:'/wellness',  color:'#a78bfa', bg:'#faf5ff' },
    { label:'Personality',   icon:'🧠', path:'/personality', color:'#7c3aed', bg:'#f5f3ff' },
    { label:'Purpose',       icon:'🧭', path:'/purpose',   color:'#0ea5e9', bg:'#eff6ff' },
    { label:'Career',        icon:'🚀', path:'/career',    color:'#f97316', bg:'#fff7ed' },
    { label:'Personal Island', icon:'🏝️', path:'/island',     color:'#06b6d4', bg:'#ecfeff' },
    { label:'Connection Score', icon:'❤️', path:'/connection', color:'#ef4444', bg:'#fff1f2' },
    { label:'SAATHI Shorts',  icon:'✨', path:'/shorts',    color:'#a78bfa', bg:'#faf5ff' },
    { label:'Daily Surprise', icon:'🎁', path:'/surprise',  color:'#7c3aed', bg:'#f5f3ff' },
    { label:'Life Library',   icon:'📚', path:'/life-library', color:'#0ea5e9', bg:'#eff6ff' },
    { label:'Hope Library',   icon:'🌟', path:'/hope-library', color:'#f59e0b', bg:'#fffbeb' },
    { label:'Calm Coloring',  icon:'🎨', path:'/coloring',     color:'#ec4899', bg:'#fdf4ff' },
    { label:'Relaxation Hub', icon:'🎵', path:'/relax',        color:'#10b981', bg:'#f0fdf4' },
    { label:'Life Map',       icon:'🗺️', path:'/life-map',     color:'#7c3aed', bg:'#f5f3ff' },
  ];

  return (
    <div style={{ maxWidth:1100, margin:'0 auto' }}>
      {/* Hero Banner */}
      <div style={{
        borderRadius:24, padding:'32px 36px', marginBottom:24,
        background:'linear-gradient(135deg,#7c3aed 0%,#a78bfa 50%,#f97316 100%)',
        color:'white', position:'relative', overflow:'hidden'
      }}>
        <div style={{ position:'absolute', top:-40, right:-40, width:200, height:200,
          borderRadius:'50%', background:'rgba(255,255,255,0.08)' }} />
        <div style={{ position:'absolute', bottom:-30, right:80, width:120, height:120,
          borderRadius:'50%', background:'rgba(255,255,255,0.06)' }} />

        <p style={{ fontSize:14, opacity:.9, marginBottom:4 }}>{greeting},</p>
        <h1 style={{ fontFamily:'Poppins', fontSize:30, fontWeight:700, marginBottom:8 }}>
          {user?.fullName?.split(' ')[0] || 'Friend'} ✨
        </h1>
        <p style={{ opacity:.85, fontSize:14, maxWidth:520 }}>{data?.dailyWisdom}</p>

        <div style={{ display:'flex', gap:16, marginTop:22, flexWrap:'wrap' }}>
          {[
            { label:'Level',    value:`${user?.level||1} · ${rpg?.title||'Seeker'}`, icon:'⚔️' },
            { label:'XP',       value:(user?.xpPoints||0).toLocaleString(),           icon:'⭐' },
            { label:'Streak',   value:`${user?.streakDays||0} days`,                  icon:'🔥' },
            { label:'Mood',     value:data?.todayMood ? MOOD_EMOJI[data.todayMood] : '—', icon:null },
            { label:'Quests',   value:`${completedQuests}/${totalQuests}`,             icon:'🗡️' },
          ].map(({ label, value, icon }) => (
            <div key={label} style={{ background:'rgba(255,255,255,0.15)',
              borderRadius:12, padding:'9px 16px', backdropFilter:'blur(10px)' }}>
              <p style={{ fontSize:10, opacity:.75, marginBottom:1 }}>{label}</p>
              <p style={{ fontSize:18, fontWeight:700, fontFamily:'Poppins' }}>
                {icon ? `${icon} ` : ''}{value}
              </p>
            </div>
          ))}
        </div>

        {/* XP Bar */}
        {rpg && (
          <div style={{ marginTop:18, maxWidth:400 }}>
            <div style={{ display:'flex', justifyContent:'space-between', fontSize:11, opacity:.8, marginBottom:4 }}>
              <span>Progress to Level {(user?.level||1)+1}</span>
              <span>{progressPct}%</span>
            </div>
            <div style={{ background:'rgba(255,255,255,0.2)', borderRadius:99, height:7, overflow:'hidden' }}>
              <div style={{ height:'100%', borderRadius:99, background:'rgba(255,255,255,0.9)',
                width:`${progressPct}%`, transition:'width 1s ease' }} />
            </div>
          </div>
        )}
      </div>

      {/* Pet + Challenge Row */}
      <div style={{ display:'grid', gridTemplateColumns: pet?.hasPet ? '1fr 1fr' : '1fr', gap:16, marginBottom:20 }}>
        {/* Daily Challenge */}
        {data?.dailyChallenge && (
          <div style={{ borderRadius:16, padding:'16px 20px',
            background:'linear-gradient(135deg,#fff7ed,#fef3c7)',
            border:'1px solid #fed7aa', display:'flex', alignItems:'center', gap:12 }}>
            <span style={{ fontSize:28 }}>🎯</span>
            <div>
              <p style={{ fontWeight:700, fontSize:11, color:'#92400e', marginBottom:2 }}>TODAY'S CHALLENGE</p>
              <p style={{ color:'#78350f', fontSize:14 }}>{data.dailyChallenge}</p>
            </div>
          </div>
        )}

        {/* Pet Status */}
        {pet?.hasPet && (
          <Link to="/pet" style={{ textDecoration:'none' }}>
            <div style={{ borderRadius:16, padding:'16px 20px',
              background:'linear-gradient(135deg,#fdf4ff,#f0fdf4)',
              border:'1px solid #e9d5ff', display:'flex', alignItems:'center', gap:12,
              cursor:'pointer', transition:'transform 0.2s' }}
              onMouseEnter={e => e.currentTarget.style.transform='translateY(-2px)'}
              onMouseLeave={e => e.currentTarget.style.transform='none'}>
              <span style={{ fontSize:36 }}>{pet.emoji}</span>
              <div>
                <p style={{ fontWeight:700, fontSize:14, color:'#7c3aed' }}>{pet.pet?.name}</p>
                <p style={{ fontSize:12, color:'var(--text-secondary)' }}>{pet.message}</p>
                <div style={{ display:'flex', gap:8, marginTop:4 }}>
                  <span style={{ fontSize:11, color:'#ec4899' }}>😊 {pet.pet?.happiness}%</span>
                  <span style={{ fontSize:11, color:'#f59e0b' }}>⚡ {pet.pet?.energy}%</span>
                </div>
              </div>
            </div>
          </Link>
        )}
      </div>

      {/* Quick Stats */}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:14, marginBottom:22 }}>
        {quickStats.map(({ label, value, icon, color, bg, path }) => (
          <Link key={label} to={path} style={{ textDecoration:'none' }}>
            <div className="card" style={{ padding:18 }}
              onMouseEnter={e => e.currentTarget.style.transform='translateY(-3px)'}
              onMouseLeave={e => e.currentTarget.style.transform='none'}
              style={{ padding:18, cursor:'pointer', transition:'transform 0.2s' }}>
              <div style={{ width:38, height:38, borderRadius:11, background:bg,
                display:'flex', alignItems:'center', justifyContent:'center',
                color, marginBottom:10 }}>{icon}</div>
              <p style={{ fontSize:26, fontWeight:700, fontFamily:'Poppins', color }}>{value}</p>
              <p style={{ fontSize:11, color:'var(--text-secondary)', marginTop:1 }}>{label}</p>
            </div>
          </Link>
        ))}
      </div>

      {/* Quick Actions Grid */}
      <div className="card" style={{ marginBottom:20 }}>
        <h2 style={{ fontFamily:'Poppins', fontWeight:600, marginBottom:14, fontSize:15 }}>Quick Actions</h2>
        <div style={{ display:'grid', gridTemplateColumns:'repeat(6,1fr)', gap:10 }}>
          {quickActions.map(({ label, icon, path, color, bg }) => (
            <Link key={label} to={path} style={{ textDecoration:'none' }}>
              <div style={{ textAlign:'center', padding:'14px 6px', borderRadius:12,
                background:bg, cursor:'pointer', transition:'transform 0.2s',
                border:`1px solid ${color}30` }}
                onMouseEnter={e => e.currentTarget.style.transform='translateY(-3px) scale(1.02)'}
                onMouseLeave={e => e.currentTarget.style.transform='none'}>
                <div style={{ fontSize:26, marginBottom:5 }}>{icon}</div>
                <p style={{ fontSize:10, fontWeight:600, color, lineHeight:1.3 }}>{label}</p>
              </div>
            </Link>
          ))}
        </div>
      </div>

      {/* Mood Trend */}
      {data?.recentMoods?.length > 0 && (
        <div className="card">
          <h2 style={{ fontFamily:'Poppins', fontWeight:600, marginBottom:14, fontSize:15 }}>
            Your Week in Moods 🌈
          </h2>
          <div style={{ display:'flex', gap:8, flexWrap:'wrap' }}>
            {data.recentMoods.map((m, i) => (
              <div key={i} style={{ textAlign:'center', padding:'10px 12px',
                borderRadius:11, background:'var(--soft-gray)', flex:1, minWidth:60 }}>
                <div style={{ fontSize:22 }}>{MOOD_EMOJI[m.mood] || '😐'}</div>
                <p style={{ fontSize:10, color:'var(--text-muted)', marginTop:3 }}>
                  {new Date(m.date).toLocaleDateString('en',{weekday:'short'})}
                </p>
                <p style={{ fontSize:10, color:'var(--text-secondary)' }}>⚡{m.energy}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      <style>{`@keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-10px)}}`}</style>
    </div>
  );
}
